// Some portions generated by Claude

package org.eclipse.rdf4j.sail.lmdb.sketch;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertNull;

import java.util.List;

import org.eclipse.rdf4j.sail.lmdb.sketch.OmniWitnessSet.FallbackReason;
import org.eclipse.rdf4j.sail.lmdb.sketch.OmniWitnessSet.SourceKind;
import org.junit.jupiter.api.Test;

/**
 * Witness hashes from different {@link SourceKind}s live in different salt domains. Union and subtraction must operate
 * independently per kind: the primary result is the best-ranked per-kind result, other kinds ride along as
 * alternatives, and mixed-kind inputs are never relabeled as {@link SourceKind#BASE}.
 */
class OmniWitnessAccumulatorSourceKindTest {

	@Test
	void maxUnionOfMixedKindsNeverRelabelsToBase() {
		OmniWitnessSet subject = witnesses(SourceKind.SUBJECT_COHORT, 0.5d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 1L, 2L }, new double[] { 1.0d, 1.0d });
		OmniWitnessSet object = witnesses(SourceKind.OBJECT_COHORT, 0.5d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 3L }, new double[] { 1.0d });

		OmniWitnessSet union = OmniWitnessAccumulator.maxUnion(List.of(subject, object));

		assertEquals(SourceKind.SUBJECT_COHORT, union.sourceKind(),
				"the better-ranked kind (more retained witnesses) must win, never BASE");
		assertEquals(2, union.retainedWitnessCount(), "the primary must only contain same-kind hashes");
		assertEquals(1L, union.hashAt(0));
		assertEquals(2L, union.hashAt(1));
		assertNull(union.candidateFor(SourceKind.BASE), "no input contributed BASE witnesses");

		OmniWitnessSet objectAlternative = union.candidateFor(SourceKind.OBJECT_COHORT);
		assertNotNull(objectAlternative, "the losing kind must be retained as an alternative");
		assertEquals(1, objectAlternative.retainedWitnessCount());
		assertEquals(3L, objectAlternative.hashAt(0));
	}

	@Test
	void maxUnionMergesSameKindWitnessesByMaxWeight() {
		OmniWitnessSet first = witnesses(SourceKind.SUBJECT_COHORT, 0.5d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 1L, 2L }, new double[] { 2.0d, 1.0d });
		OmniWitnessSet second = witnesses(SourceKind.SUBJECT_COHORT, 0.25d, 0.8d, FallbackReason.NONE, 0.0d,
				new long[] { 2L, 4L }, new double[] { 5.0d, 1.0d });

		OmniWitnessSet union = OmniWitnessAccumulator.maxUnion(List.of(first, second));

		assertEquals(SourceKind.SUBJECT_COHORT, union.sourceKind());
		assertEquals(3, union.retainedWitnessCount());
		assertEquals(2.0d, union.weightAt(0), 0.0d);
		assertEquals(5.0d, union.weightAt(1), 0.0d, "duplicate hashes take the max weight across inputs");
		assertEquals(1.0d, union.weightAt(2), 0.0d);
		assertEquals(0.25d, union.samplingProbability(), 0.0d);
		assertEquals(0.8d, union.confidence(), 0.0d);
		assertEquals((2.0d + 5.0d + 1.0d) / 0.25d, union.estimatedRows(), 1e-9);
	}

	@Test
	void maxUnionPrefersCleanEvidenceOverFallback() {
		OmniWitnessSet lossy = witnesses(SourceKind.SUBJECT_COHORT, 0.5d, 0.9d, FallbackReason.SAMPLE_LOSS, 8.0d,
				new long[] { 1L, 2L, 3L }, new double[] { 1.0d, 1.0d, 1.0d });
		OmniWitnessSet clean = witnesses(SourceKind.OBJECT_COHORT, 0.5d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 7L }, new double[] { 1.0d });

		OmniWitnessSet union = OmniWitnessAccumulator.maxUnion(List.of(lossy, clean));

		assertEquals(SourceKind.OBJECT_COHORT, union.sourceKind(),
				"clean evidence outranks a fallback result regardless of retained counts");
		assertEquals(FallbackReason.NONE, union.fallbackReason(),
				"a fallback on one kind must not contaminate the clean winner");

		OmniWitnessSet lossyAlternative = union.candidateFor(SourceKind.SUBJECT_COHORT);
		assertNotNull(lossyAlternative);
		assertEquals(FallbackReason.SAMPLE_LOSS, lossyAlternative.fallbackReason(),
				"per-kind fallback metadata stays on that kind's result");
	}

	@Test
	void maxUnionCollectsKindsThroughAlternatives() {
		OmniWitnessSet firstArm = witnesses(SourceKind.BASE, 1.0d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 1L }, new double[] { 1.0d })
						.withAlternativeCandidates(
								witnesses(SourceKind.SUBJECT_COHORT, 0.25d, 0.9d, FallbackReason.NONE,
										0.0d, new long[] { 10L }, new double[] { 1.0d }));
		OmniWitnessSet secondArm = witnesses(SourceKind.BASE, 1.0d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 2L }, new double[] { 1.0d })
						.withAlternativeCandidates(
								witnesses(SourceKind.SUBJECT_COHORT, 0.25d, 0.9d, FallbackReason.NONE,
										0.0d, new long[] { 11L }, new double[] { 1.0d }));

		OmniWitnessSet union = OmniWitnessAccumulator.maxUnion(List.of(firstArm, secondArm));

		assertEquals(SourceKind.BASE, union.sourceKind(),
				"equal retained counts fall through to the higher sampling probability");
		assertEquals(2, union.retainedWitnessCount());

		OmniWitnessSet cohortAlternative = union.candidateFor(SourceKind.SUBJECT_COHORT);
		assertNotNull(cohortAlternative, "alternatives present on every input must union into an alternative");
		assertEquals(2, cohortAlternative.retainedWitnessCount());
		assertEquals(10L, cohortAlternative.hashAt(0));
		assertEquals(11L, cohortAlternative.hashAt(1));
	}

	@Test
	void subtractOnlyRemovesSameKindWitnesses() {
		OmniWitnessSet input = witnesses(SourceKind.SUBJECT_COHORT, 0.5d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 1L, 2L }, new double[] { 1.0d, 1.0d });
		OmniWitnessSet removals = witnesses(SourceKind.OBJECT_COHORT, 0.5d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 1L }, new double[] { 1.0d });

		OmniWitnessSet result = OmniWitnessAccumulator.subtract(input, removals);

		assertEquals(SourceKind.SUBJECT_COHORT, result.sourceKind(), "subtraction must not relabel the input kind");
		assertEquals(2, result.retainedWitnessCount(),
				"hashes from a different salt domain must not remove input witnesses");
	}

	@Test
	void subtractRemovesWithinEachKindAndKeepsAlternatives() {
		OmniWitnessSet input = witnesses(SourceKind.BASE, 1.0d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 1L, 2L }, new double[] { 1.0d, 1.0d })
						.withAlternativeCandidates(
								witnesses(SourceKind.SUBJECT_COHORT, 0.25d, 0.9d, FallbackReason.NONE,
										0.0d, new long[] { 5L, 6L }, new double[] { 1.0d, 1.0d }));
		OmniWitnessSet removals = witnesses(SourceKind.BASE, 1.0d, 0.9d, FallbackReason.NONE, 0.0d,
				new long[] { 1L }, new double[] { 1.0d })
						.withAlternativeCandidates(
								witnesses(SourceKind.SUBJECT_COHORT, 0.25d, 0.9d, FallbackReason.NONE,
										0.0d, new long[] { 5L }, new double[] { 1.0d }));

		OmniWitnessSet result = OmniWitnessAccumulator.subtract(input, removals);

		assertEquals(SourceKind.BASE, result.sourceKind());
		assertEquals(1, result.retainedWitnessCount());
		assertEquals(2L, result.hashAt(0));

		OmniWitnessSet cohortSurvivor = result.candidateFor(SourceKind.SUBJECT_COHORT);
		assertNotNull(cohortSurvivor, "same-kind subtraction must run on alternatives too");
		assertEquals(1, cohortSurvivor.retainedWitnessCount());
		assertEquals(6L, cohortSurvivor.hashAt(0));
	}

	private static OmniWitnessSet witnesses(SourceKind kind, double samplingProbability, double confidence,
			FallbackReason fallbackReason, double minimumDetectableRows, long[] hashes, double[] weights) {
		return OmniWitnessSet
				.fromSortedUnsigned(hashes.clone(), weights.clone(), hashes.length, samplingProbability, confidence,
						fallbackReason, minimumDetectableRows)
				.withSourceKind(kind);
	}
}
